"""matplotlib.tri — unstructured triangular grid support."""

import numpy as _np


class Triangulation:
    def __init__(self, x, y, triangles=None, mask=None):
        self.x = _np.asarray(x, dtype=float)
        self.y = _np.asarray(y, dtype=float)
        if triangles is not None:
            self.triangles = _np.asarray(triangles, dtype=int)
        else:
            # Simple Delaunay-like triangulation stub
            n = len(x)
            self.triangles = _np.array([[i, (i+1) % n, (i+2) % n] for i in range(n - 2)])
        self.mask = mask

    def get_masked_triangles(self):
        if self.mask is not None:
            return self.triangles[~_np.asarray(self.mask)]
        return self.triangles

    @property
    def edges(self):
        return _np.array([])

    @property
    def neighbors(self):
        return _np.array([])

    def set_mask(self, mask):
        self.mask = mask

    def get_trifinder(self):
        return None

    @staticmethod
    def get_from_args_and_kwargs(*args, **kwargs):
        return Triangulation(*args[:2], **kwargs), args[2:]


class TriContourSet:
    def __init__(self, ax, *args, **kwargs):
        self.ax = ax
        self.levels = kwargs.get('levels', [])


class UniformTriRefiner:
    def __init__(self, triangulation):
        self.triangulation = triangulation

    def refine_triangulation(self, subdiv=3, return_tri_index=False):
        return self.triangulation

    def refine_field(self, z, triinterpolator=None, subdiv=3):
        return self.triangulation, z


class TriInterpolator:
    def __init__(self, triangulation, z, trifinder=None):
        self.triangulation = triangulation
        self.z = z


class LinearTriInterpolator(TriInterpolator):
    def __call__(self, x, y):
        return _np.zeros_like(_np.asarray(x))


class CubicTriInterpolator(TriInterpolator):
    def __init__(self, triangulation, z, kind='min_E', trifinder=None, dz=None):
        super().__init__(triangulation, z, trifinder)

    def __call__(self, x, y):
        return _np.zeros_like(_np.asarray(x))


class TriAnalyzer:
    def __init__(self, triangulation):
        self.triangulation = triangulation

    def get_flat_tri_mask(self, min_circle_ratio=0.01, rescale=True):
        return _np.zeros(len(self.triangulation.triangles), dtype=bool)

    def circle_ratios(self, rescale=True):
        return _np.ones(len(self.triangulation.triangles))


class TriFinder:
    def __init__(self, triangulation):
        self.triangulation = triangulation


class TrapezoidMapTriFinder(TriFinder):
    pass
